mapper.select:
SELECT ROW_NUMBER() OVER ( PARTITION BY A.YYYYMM, A.SEL_CODE, A.SITE, A.도우코드 ORDER BY A.생성시각 ) AS ROW_SEQ, A.YYYYMM, A.SEL_CODE, A.SITE AS SITE_ORG, CASE WHEN A.SITE = 'HQ' THEN '본사' WHEN A.SITE = 'VN' THEN 'VINA' END AS SITE, CASE WHEN A.도우코드 LIKE '%D' THEN '개발' WHEN A.도우코드 IS NOT NULL AND A.도우코드 != '' THEN '양산' ELSE NULL END AS 구분, A.도우코드, A.RMA_IN, A.RMA_OUT, A.생성자, A.생성시각, B.OUT_MONTH FROM DOI_RMA_INOUT A LEFT JOIN DOI_PROD_SUBUL B ON A.도우코드 = B.도우코드 AND A.YYYYMM = B.YYYYMM AND A.SITE = B.DW_SITE WHERE 1=1
AND A.YYYYMM = #{yyyymm}
AND A.SITE = #{site}
ORDER BY A.도우코드

mapper.update:
;WITH T AS (
   SELECT
       ROW_NUMBER() OVER (
           PARTITION BY YYYYMM, SEL_CODE, SITE, 도우코드
           ORDER BY 생성시각
       ) AS ROW_SEQ,
       *
   FROM DOI_RMA_INOUT
   WHERE YYYYMM = #{yyyymm}
     AND SEL_CODE = #{selCode}
     AND SITE = #{siteOrg}
     AND 도우코드 = #{도우코드}
   )
   UPDATE T
   SET 
       RMA_IN  = #{rmaIn},
       RMA_OUT = #{rmaOut},
       생성자   = #{생성자},
       생성시각 = SYSDATETIME()
   WHERE ROW_SEQ = #{rowSeq}

mapper.delete:
WITH T AS (
    SELECT
        ROW_NUMBER() OVER (
            PARTITION BY YYYYMM, SEL_CODE, SITE, 도우코드
            ORDER BY 생성시각
        ) AS ROW_SEQ,
        *
    FROM DOI_RMA_INOUT
    WHERE YYYYMM = #{yyyymm}
    AND SEL_CODE = #{selCode}
    AND SITE = #{siteOrg}
    AND 도우코드 = #{도우코드}
)
DELETE FROM T
WHERE ROW_SEQ = #{rowSeq}

mapper.select:
SELECT 도우코드, MODEL AS 세부모델, INCH, SITE AS 거래처, OUT_MONTH, DW_SITE AS SITE FROM DOI_PROD_SUBUL WHERE 1=1 AND OUT_MONTH > 0
AND YYYYMM = #{yyyymm}
AND DW_SITE = #{site}
AND MODEL = #{model}
ORDER BY 도우코드
